/* ─────────── SCROLL REVEAL HOOK ─────────── */
function useReveal(){
  const ref = useRef(null);
  const [visible,setVisible] = useState(false);
  useEffect(()=>{
    const el = ref.current; if(!el) return;
    const obs = new IntersectionObserver(([e])=>{
      if(e.isIntersecting){setVisible(true);obs.disconnect();}
    },{threshold:0.12});
    obs.observe(el);
    return()=>obs.disconnect();
  },[]);
  return [ref,visible];
}

/* ─────────── NAV SCROLL HOOK ─────────── */
function useScrolled(threshold = 40) {
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > threshold);
    };

    window.addEventListener('scroll', handleScroll, { passive: true });

    return () => {
      window.removeEventListener('scroll', handleScroll);
    };
  }, [threshold]);

  return scrolled;
}

/* ─────────── ANIMATED COUNTER ─────────── */
function AnimCounter({to,suffix='',duration=1600}){
  const [val,setVal]=useState(0);
  const [ref,vis]=useReveal();
  useEffect(()=>{
    if(!vis) return;
    let start=null;
    const num=parseFloat(String(to).replace(/[^0-9.]/g,''));
    const step=ts=>{
      if(!start)start=ts;
      const p=Math.min((ts-start)/duration,1);
      const ease=1-Math.pow(1-p,3);
      setVal(Math.round(ease*num));
      if(p<1)requestAnimationFrame(step);
      else setVal(num);
    };
    requestAnimationFrame(step);
  },[vis,to,duration]);
  return <span ref={ref}>{val.toLocaleString()}{suffix}</span>;
}

/* ─────────── MOBILE MENU HOOK ─────────── */
function useMobileMenu(){
  const [open,setOpen]=useState(false);
  useEffect(()=>{
    if(open){
      document.body.style.overflow='hidden';
    }else{
      document.body.style.overflow='';
    }
    return()=>{document.body.style.overflow='';};
  },[open]);
  return [open,setOpen];
}

/* ─────────── LANGUAGE HOOK ─────────── */
function useLanguage() {
  const [lang, setLang] = useState(() => {
    if (typeof window === 'undefined') return 'uk';
    const urlParams = new URLSearchParams(window.location.search);
    const urlLang = urlParams.get('lang');
    if (urlLang && ['uk', 'en', 'ru'].includes(urlLang)) return urlLang;
    const saved = localStorage.getItem('preferred-language');
    if (saved && ['uk', 'en', 'ru'].includes(saved)) return saved;
    const browserLang = navigator.language.toLowerCase();
    if (browserLang.startsWith('uk')) return 'uk';
    if (browserLang.startsWith('ru')) return 'ru';
    return 'uk';
  });
  useEffect(() => {
    localStorage.setItem('preferred-language', lang);
    document.documentElement.lang = lang;
  }, [lang]);
  return [lang, setLang, translations[lang]];
}

/* ─────────── LANGUAGE SWITCHER ─────────── */
function LanguageSwitcher({lang, setLang}) {
  const flags = { uk: '\u{1F1FA}\u{1F1E6}', en: '\u{1F1EC}\u{1F1E7}', ru: '\u{1F1F7}\u{1F1FA}' };
  const names = { uk: 'UA', en: 'EN', ru: 'RU' };
  return (
    <div className="lang-switcher">
      {['uk', 'en', 'ru'].map(l => (
        <button key={l} className={`lang-btn ${lang === l ? 'active' : ''}`}
          onClick={() => setLang(l)} title={names[l]}>
          <span className="lang-flag">{flags[l]}</span>
          <span className="lang-code">{names[l]}</span>
        </button>
      ))}
    </div>
  );
}

