/* ═══════════ PERSONAL BRAND BLOCK ═══════════ */
function PersonalBrandBlock({setPage}){
  const CX=340,CY=340,R=260;
  const nodes=[
    {icon:'🔒',text:'Персональні дані'},
    {icon:'⭐',text:'Цифрова репутація'},
    {icon:'🪙',text:'Токенізовані активи'},
    {icon:'🧩',text:'Метаресурси'},
    {icon:'📄',text:'Метаконтракти'},
    {icon:'📚',text:'Метадокументи'},
  ];
  const nodePositions=nodes.map((_,i)=>{
    const angle=(Math.PI*2*i/nodes.length)-Math.PI/2;
    return {x:CX+R*Math.cos(angle), y:CY+R*Math.sin(angle)};
  });
  const infra=[
    {name:'LINK',desc:'мережа довіри'},
    {name:'AURA',desc:'цифрова репутація'},
    {name:'PING',desc:'безпечна комунікація'},
    {name:'MARKET',desc:'ринок метаактивів'},
    {name:'CONTRIBUTING',desc:'фінансування проєктів'},
  ];

  return(
    <section className="pb-section">
      <div className="pb-inner">
        <div className="sec-tag" style={{textAlign:'center',display:'block',marginBottom:14}}>▸ Особистий бренд</div>
        <h2 className="pb-hero-title">Особистий бренд як <span>економічна система</span></h2>
        <p className="pb-hero-sub">
          У цифровій економіці Web4 людина стає центром створення цінності.
        </p>

        {/* ── ORBIT INFOGRAPHIC ── */}
        <div className="pb-orbit-wrap">
          {/* SVG orbit lines */}
          <svg className="pb-orbit-svg" viewBox="0 0 680 680">
            {/* Outer orbit circle */}
            <circle cx={CX} cy={CY} r={R} className="pb-orbit-circle-outer"/>
            {/* Inner dashed circle */}
            <circle cx={CX} cy={CY} r={160} className="pb-orbit-circle-inner"/>
            {/* Lines from center to each node */}
            {nodePositions.map((p,i)=>(
              <line key={i} x1={CX} y1={CY} x2={p.x} y2={p.y} className="pb-orbit-line"/>
            ))}
            {/* Glow dots on orbit */}
            {nodePositions.map((p,i)=>(
              <circle key={'d'+i} cx={p.x} cy={p.y} r={4} className="pb-orbit-dot"/>
            ))}
          </svg>

          {/* CSS rotating rings */}
          <div className="pb-ring-rotate"/>
          <div className="pb-ring-rotate2"/>

          {/* Center Core */}
          <div className="pb-core">
            <img className="pb-core-icon" src="data:image/webp;base64," alt="Viking" style={{width:90,height:94,objectFit:"contain"}}/>
            <div className="pb-core-name">VIKING</div>
            <div className="pb-core-role">Personal Economic Identity</div>
            <div className="pb-core-role2">Економічна одиниця</div>
          </div>

          {/* Orbit Node Labels */}
          {nodes.map((n,i)=>{
            const p=nodePositions[i];
            const pxSize=680;
            const leftPct=(p.x/pxSize*100);
            const topPct=(p.y/pxSize*100);
            const isLeft=p.x<CX;
            const isTop=p.y<CY;
            const style={
              left:leftPct+'%',
              top:topPct+'%',
              transform:`translate(${isLeft?'-100%':p.x===CX?'-50%':'0'},${isTop?'-100%':p.y===CY?'-50%':'0'})`,
              '--tx':isLeft?'-4px':'4px',
              '--ty':isTop?'-4px':'4px',
            };
            if(Math.abs(p.x-CX)<10){style.transform=`translate(-50%,${isTop?'calc(-100% - 8px)':'8px'})`}
            else if(isLeft){style.transform=`translate(calc(-100% - 12px),${isTop?'-60%':'0%'})`}
            else{style.transform=`translate(12px,${isTop?'-60%':'0%'})`}
            return(
              <div className="pb-node" key={i} style={style}>
                <span className="pb-node-icon">{n.icon}</span>
                <span className="pb-node-text">{n.text}</span>
              </div>
            );
          })}
        </div>

        {/* Infrastructure Layer */}
        <div className="pb-infra">
          {infra.map((s,i)=>(
            <div className="pb-infra-card" key={i}>
              <div className="pb-infra-name">{s.name}</div>
              <div className="pb-infra-desc">{s.desc}</div>
            </div>
          ))}
        </div>

        {/* Manifesto */}
        <div className="pb-manifesto">
          <div className="pb-manifesto-lead">Цифрова ідентичність — персональна економічна модель</div>
          <div className="pb-manifesto-text">
            Я керую своїми даними, активами та цифровою репутацією.
            Я взаємодію з людьми, ринком та сервісами нової цифрової економіки.
            Я створюю власний капітал, який має реальну цінність.
          </div>
          <div style={{fontFamily:"'JetBrains Mono',monospace",fontSize:9,letterSpacing:3,color:'var(--acc)',textTransform:'uppercase',marginBottom:14}}>
            Цей капітал формується через:
          </div>
          <div className="pb-manifesto-list">
            {['мої можливості','мої знання','мої взаємодії','мої комунікації','мої рішення','мої дії'].map((c,i)=>(
              <div className="pb-manifesto-chip" key={i}>{c}</div>
            ))}
          </div>
          <div className="pb-manifesto-final">
            У <span className="pb-final-blue">WEB4</span> КОЖНА ЛЮДИНА МОЖЕ СТАТИ <span className="pb-final-blue">ЕКОНОМІЧНОЮ СИСТЕМОЮ</span>
          </div>
        </div>
      </div>
    </section>
  );
}

const PAGES = ['home','system','token','onespace','cases','metaresources','contact'];
const PAGE_LABELS = {
  home:'Головна',system:'Система Bitbon',token:'Цифровий актив Bitbon',
  onespace:'OneSpace',metaresources:'Метаресурсы',cases:'Web 4.0',contact:'Контакт'
};

/* ─── COMPONENTS ─── */

function Nav({page,setPage}){
  const scrolled = useScrolled();
  const [mobileMenuOpen,setMobileMenuOpen]=useMobileMenu();
  const [lang, setLang, t] = useLanguage();
  const labels = t && t.pages && t.pages.labels ? t.pages.labels : PAGE_LABELS;
  return(
    <>
    <nav className={`nav${scrolled?' scrolled':''}`}>
      <div className="nav-brand" onClick={()=>setPage('home')} style={{cursor:'pointer',flexShrink:0}}>
        <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:20,letterSpacing:3,lineHeight:1,whiteSpace:'nowrap'}}>
          <span style={{color:'var(--white)',fontWeight:900}}>BITBON</span>{' '}
          <span style={{color:'var(--acc)',fontWeight:900}}>SYSTEM</span>
        </div>
        <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:20,letterSpacing:3,color:'var(--white)',marginTop:4,lineHeight:1}}>
          {t && t.pages ? t.pages.nav.partner : 'ПАРТНЕР'}
        </div>
      </div>
      
        <button 
          className={`nav-toggle ${mobileMenuOpen?'open':''}`}
          onClick={()=>setMobileMenuOpen(!mobileMenuOpen)}
          aria-label="Toggle menu"
        >
          <span></span>
          <span></span>
          <span></span>
        </button>
        
        <div className={`nav-links ${mobileMenuOpen?'open':''}`}>
        {PAGES.filter(p=>p!=='home').map(p=>(
          <span key={p} className={`nav-link${page===p?' active':''}`} onClick={()=>{setPage(p);setMobileMenuOpen(false);}}>
            {labels[p] || PAGE_LABELS[p]}
          </span>
        ))}
      </div>
      <div style={{flexShrink:0,textAlign:'right',display:'flex',alignItems:'center',gap:12}}>
        <LanguageSwitcher lang={lang} setLang={setLang}/>
        <div>
          <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:20,letterSpacing:3,color:'var(--white)',fontWeight:900,lineHeight:1,whiteSpace:'nowrap',cursor:'pointer'}} onClick={()=>{setPage('contact');setMobileMenuOpen(false);}}>
            Oleksandr Zhdanenko
          </div>
          <div style={{marginTop:4,display:'flex',justifyContent:'flex-end'}}>
            <button className="nav-cta" onClick={()=>{setPage('contact');setMobileMenuOpen(false);}}>
              {t ? t.nav.consultation : 'Консультація'}
            </button>
          </div>
        </div>
      </div>
    </nav>
      
      <div 
        className={`nav-overlay ${mobileMenuOpen?'open':''}`}
        onClick={()=>setMobileMenuOpen(false)}
      />
    </>
  );
}

function Reveal({children,dir='',delay=0,className=''}){
  const [ref,vis]=useReveal();
  const cls=`reveal${dir?'-'+dir:''} ${vis?'vis':''} ${className}`.trim();
  return <div ref={ref} className={cls} style={{transitionDelay:`${delay}ms`}}>{children}</div>;
}

function SectionHeader({tag,title,sub}){
  const [ref,vis]=useReveal();
  return(
    <div className={`sec-header reveal ${vis?'vis':''}`} ref={ref}>
      {tag&&<div className="sec-tag">▸ {tag}</div>}
      <h2 className="sec-title">{title}</h2>
      {sub&&<p className="sec-sub">{sub}</p>}
    </div>
  );
}

