/* ─────────── CAROUSEL COMPONENT ─────────── */
function Carousel(){
  const trackRef = useRef(null);
  const [canLeft, setCanLeft] = useState(false);
  const [canRight, setCanRight] = useState(true);
  const [dragging, setDragging] = useState(false);
  const dragState = useRef({ startX:0, scrollLeft:0 });

  const checkScroll = useCallback(()=>{
    const el = trackRef.current; if(!el) return;
    setCanLeft(el.scrollLeft > 10);
    setCanRight(el.scrollLeft < el.scrollWidth - el.clientWidth - 10);
  },[]);

  useEffect(()=>{
    const el = trackRef.current; if(!el) return;
    el.addEventListener('scroll', checkScroll, {passive:true});
    checkScroll();
    return ()=> el.removeEventListener('scroll', checkScroll);
  },[checkScroll]);

  const scroll = (dir) => {
    const el = trackRef.current; if(!el) return;
    el.scrollBy({ left: dir * 380, behavior:'smooth' });
  };

  const onMouseDown = (e) => {
    const el = trackRef.current; if(!el) return;
    setDragging(true);
    dragState.current = { startX: e.pageX - el.offsetLeft, scrollLeft: el.scrollLeft };
    el.style.cursor = 'grabbing';
  };
  const onMouseMove = (e) => {
    if(!dragging) return;
    const el = trackRef.current; if(!el) return;
    e.preventDefault();
    const x = e.pageX - el.offsetLeft;
    el.scrollLeft = dragState.current.scrollLeft - (x - dragState.current.startX);
  };
  const onMouseUp = () => {
    setDragging(false);
    const el = trackRef.current; if(el) el.style.cursor = 'grab';
  };

  const [ref,vis] = useReveal();

  return(
    <div ref={ref} className={`reveal ${vis?'vis':''}`}>
      <div className="carousel-header">
        <div>
          <div className="carousel-tag">▸ Галерея метаресурсів</div>
          <h2 className="carousel-title">Метаресурси</h2>
          <p className="carousel-sub">Знайди свій бренд або бізнес. Кожна галузь може бути токенізована.</p>
        </div>
        <div className="carousel-nav">
          <button className={`car-btn ${!canLeft?'disabled':''}`} onClick={()=>scroll(-1)} aria-label="Prev">
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M15 18l-6-6 6-6"/></svg>
          </button>
          <button className={`car-btn ${!canRight?'disabled':''}`} onClick={()=>scroll(1)} aria-label="Next">
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M9 18l6-6-6-6"/></svg>
          </button>
        </div>
      </div>
      <div className="carousel-track"
        ref={trackRef}
        onMouseDown={onMouseDown}
        onMouseMove={onMouseMove}
        onMouseUp={onMouseUp}
        onMouseLeave={onMouseUp}
      >
        {META_RESOURCES.map((m)=>(
          <div className="meta-card" key={m.id} style={{'--card-accent': m.color}}>
            <div className="meta-card-glow"/>
            <div className="meta-type-badge" data-type={m.type}>
              {m.type === 'Бізнес' ? '◆' : m.type === 'Експерт' ? '★' : '✦'} {m.type}
            </div>
            <div className="meta-card-top">
              <span className="meta-icon">{m.icon}</span>
              <span className="meta-cat">{m.cat}</span>
            </div>
            <div className="meta-card-title">{m.title}</div>
            <div className="meta-card-desc">{m.desc}</div>
            <div className="meta-card-footer">
              <span className="meta-stat">{m.stats}</span>
              <span className="meta-arrow">Детальніше →</span>
            </div>
          </div>
        ))}
      </div>
      <div className="carousel-dots">
        {META_RESOURCES.map((_,i)=>(
          <div key={i} className="c-dot" style={{background: META_RESOURCES[i].color, opacity:.35}}/>
        ))}
      </div>
    </div>
  );
}

/* ── KPI PROGRESS BAR COMPONENT ── */
function KpiBar({label, value, percent}){
  const [ref,vis] = useReveal();
  return(
    <div className="kpi-bar-item" ref={ref}>
      <div className="kpi-bar-header">
        <span className="kpi-bar-label">{label}</span>
        <span className="kpi-bar-val">{value}</span>
      </div>
      <div className="kpi-bar-track">
        <div className="kpi-bar-fill" style={{width: vis ? `${percent}%` : '0%'}}/>
      </div>
    </div>
  );
}

